{
    "openapi": "3.0.0",
    "info": {
        "title": "Repo Provisioner API",
        "version": "1.0.0",
        "description": "Clones repos, scans them for security issues, and uploads clean repos into an OpenShell sandbox."
    },
    "paths": {
        "/repo/provision": {
            "post": {
                "summary": "Provision a repository",
                "description": "Clone a GitHub repo, scan it for security issues, and upload it into the sandbox if clean.",
                "security": [
                    {
                        "bearerAuth": []
                    }
                ],
                "requestBody": {
                    "required": true,
                    "content": {
                        "application/json": {
                            "schema": {
                                "type": "object",
                                "required": [
                                    "repo"
                                ],
                                "properties": {
                                    "repo": {
                                        "type": "string",
                                        "description": "GitHub repo in org/name format"
                                    },
                                    "ref": {
                                        "type": "string",
                                        "description": "Git ref to check out (default: main)",
                                        "default": "main"
                                    },
                                    "dest": {
                                        "type": "string",
                                        "description": "Sandbox path to upload the cloned repo to"
                                    },
                                    "sandbox": {
                                        "type": "string",
                                        "description": "Sandbox name for uploading the repo (use $(hostname | sed 's/^sandbox-//') from inside the sandbox)"
                                    }
                                }
                            }
                        }
                    }
                },
                "responses": {
                    "200": {
                        "description": "Provisioning result",
                        "content": {
                            "application/json": {
                                "schema": {
                                    "type": "object",
                                    "properties": {
                                        "id": {
                                            "type": "string"
                                        },
                                        "status": {
                                            "type": "string",
                                            "enum": [
                                                "completed",
                                                "rejected",
                                                "failed"
                                            ]
                                        },
                                        "repo": {
                                            "type": "string"
                                        },
                                        "ref": {
                                            "type": "string"
                                        },
                                        "findings": {
                                            "type": "array",
                                            "items": {
                                                "type": "object",
                                                "properties": {
                                                    "file": {
                                                        "type": "string"
                                                    },
                                                    "issue": {
                                                        "type": "string"
                                                    },
                                                    "severity": {
                                                        "type": "string",
                                                        "enum": [
                                                            "high",
                                                            "medium"
                                                        ]
                                                    }
                                                }
                                            }
                                        },
                                        "error": {
                                            "type": "string"
                                        }
                                    }
                                }
                            }
                        }
                    },
                    "401": {
                        "description": "Missing or invalid bearer token"
                    }
                }
            }
        },
        "/repo/status/{id}": {
            "get": {
                "summary": "Check provisioning operation status",
                "description": "Retrieve the status and results of a provisioning operation by its ID.",
                "security": [
                    {
                        "bearerAuth": []
                    }
                ],
                "parameters": [
                    {
                        "name": "id",
                        "in": "path",
                        "required": true,
                        "schema": {
                            "type": "string"
                        },
                        "description": "Provisioning operation ID"
                    }
                ],
                "responses": {
                    "200": {
                        "description": "Operation status",
                        "content": {
                            "application/json": {
                                "schema": {
                                    "type": "object",
                                    "properties": {
                                        "id": {
                                            "type": "string"
                                        },
                                        "status": {
                                            "type": "string"
                                        },
                                        "repo": {
                                            "type": "string"
                                        },
                                        "ref": {
                                            "type": "string"
                                        },
                                        "findings": {
                                            "type": "array"
                                        },
                                        "error": {
                                            "type": "string"
                                        }
                                    }
                                }
                            }
                        }
                    },
                    "404": {
                        "description": "Operation not found"
                    },
                    "401": {
                        "description": "Missing or invalid bearer token"
                    }
                }
            }
        }
    },
    "components": {
        "securitySchemes": {
            "bearerAuth": {
                "type": "http",
                "scheme": "bearer"
            }
        }
    }
}

